// Validate API token
const expectedToken = process.env.API_TOKEN || '';
if (expectedToken) {
  const headers = $input.first().json.headers || {};
  const query = $input.first().json.query || {};
  const token = headers['x-api-token'] || headers['X-Api-Token'] || headers['X-API-TOKEN'] || Object.entries(headers).find(([k]) => k.toLowerCase() === 'x-api-token')?.[1] || query.token || '';
  if (token !== expectedToken) throw new Error('Unauthorized');
}

const axios = require('axios');
const crypto = require('crypto');

const BASE_URL = 'https://www.nemlig.com';
const username = process.env.NEMLIG_USER || '';
const password = process.env.NEMLIG_PASS || '';

const commonHeaders = {
  'Accept': 'application/json, text/plain, */*',
  'Content-Type': 'application/json',
  'User-Agent': 'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36',
  'Device-Size': 'desktop', 'Platform': 'web', 'Version': '11.201.0',
};

let cookies = {};
function parseCookies(resp) {
  const setCookies = resp.headers['set-cookie'] || [];
  for (const c of setCookies) {
    const parts = c.split(';')[0].split('=');
    cookies[parts[0].trim()] = parts.slice(1).join('=').trim();
  }
}
function cookieHeader() {
  return Object.entries(cookies).map(([k, v]) => k + '=' + v).join('; ');
}

async function req(method, url, data, extraHeaders) {
  const h = { ...commonHeaders, 'X-Correlation-Id': crypto.randomUUID(), 'Cookie': cookieHeader(), ...extraHeaders };
  const resp = await axios({ method, url, data, headers: h, validateStatus: () => true });
  parseCookies(resp);
  if (resp.status >= 400) throw new Error(method + ' ' + url + ' returned ' + resp.status);
  return resp;
}

// Auth
const xsrfResp = await req('get', BASE_URL + '/webapi/AntiForgery');
const tokenResp = await req('get', BASE_URL + '/webapi/Token');
const loginResp = await req('post', BASE_URL + '/webapi/login', {
  Username: username, Password: password,
  CheckForExistingProducts: true, DoMerge: true, AppInstalled: false, SaveExistingBasket: false
}, { 'X-XSRF-TOKEN': xsrfResp.data.Value, 'Authorization': 'Bearer ' + tokenResp.data.access_token, 'Referer': BASE_URL + '/login' });
if (!loginResp.data.RedirectUrl) throw new Error('Login failed');

const freshToken = (await req('get', BASE_URL + '/webapi/Token')).data.access_token;
const freshXsrf = (await req('get', BASE_URL + '/webapi/AntiForgery')).data.Value;
const authHeaders = { 'X-XSRF-TOKEN': freshXsrf, 'Authorization': 'Bearer ' + freshToken, 'Referer': BASE_URL + '/' };

// Handle actions
const action = $input.first().json.body.action || '';
if (action === 'clear') {
  await req('post', BASE_URL + '/webapi/basket/ClearBasket', {}, authHeaders);
  return [{ json: { cleared: true, added: 0, failed: 0, totalItems: 0 } }];
}
if (action === 'view') {
  const basketResp = await req('get', BASE_URL + '/webapi/basket/GetBasket', null, authHeaders);
  const lines = basketResp.data.Lines || [];
  const items = lines.map(function(l) { return { name: l.Name, qty: l.Quantity, price: l.Price, image: l.PrimaryImage }; });
  return [{ json: { action: 'view', items: items, count: lines.length, total: basketResp.data.TotalPrice || 0 } }];
}

// Add items to basket
const items = $input.first().json.body.items || [];
if (items.length === 0) throw new Error('No items to add');

const results = [];
for (const item of items) {
  try {
    if (results.length > 0) await new Promise(r => setTimeout(r, 1000));
    await req('post', BASE_URL + '/webapi/basket/AddToBasket', {
      ProductId: String(item.productId), quantity: item.quantity || 1,
      AffectPartialQuantity: false, disableQuantityValidation: false
    }, authHeaders);
    results.push({ productId: item.productId, name: item.name, success: true });
  } catch (e) {
    results.push({ productId: item.productId, name: item.name, success: false, error: e.message });
  }
}

const added = results.filter(r => r.success).length;
const failed = results.filter(r => !r.success).length;
return [{ json: { results, added, failed, totalItems: items.length } }];
